     if(window.mobileApp) window.mobileApp.postMessage({ detail: { type: 'ERROR', message: e.toString() }});
  }
})();

score.parseScript:
(function () {
    // 防重複送出鎖
    if (window._hasParsedScore) return;


    var rows = document.querySelectorAll("tr.tr_data");
    if (rows.length === 0) return;


    var results = [];


    rows.forEach(function (row) {
        var tds = row.querySelectorAll("td");
        // 確保欄位數量正確 (至少要有 8 欄才包含上下學期成績)
        if (tds.length < 8) return;


        // 整理基本資訊
        var yearLabel = tds[1].innerText.replace(/[\n\r\s]+/g, ""); // 範例：一(年), 一(上), 一(下)
        var subject = tds[2].innerText.trim();
        var type = tds[3].innerText.replace(/[\n\r\s]+/g, ""); // 範例：必, 選, 博雅
        var credit = tds[4].innerText.trim();


        // 定義處理單一學期的內部函式
        function processSemester(td, semSuffix) {
            var passStatus = td.getAttribute("data-pass_status");
            var scoreVal = td.getAttribute("data-score") || "";


            // 若為 '-' 代表該學期沒這堂課，或是資料為空，直接略過
            if (!passStatus || passStatus === "-") return;


            var isPass = null;
            var statusText = "未知";


            // 狀態映射邏輯 (處理 P, T, F, ?, N, W)
            if (passStatus.indexOf("P") !== -1 || passStatus.indexOf("T") !== -1) {
                isPass = true; // 綠色
                statusText = passStatus.indexOf("T") !== -1 ? "抵免/免修" : "通過";
            } else if (
                passStatus.indexOf("F") !== -1 ||
                passStatus.indexOf("W") !== -1
            ) {
                isPass = false; // 紅色
                statusText = passStatus.indexOf("W") !== -1 ? "專案退選" : "不及格";
            } else if (passStatus.indexOf("?") !== -1) {
                isPass = null; // 黃/灰色
                statusText = "修業中";
            } else if (passStatus.indexOf("N") !== -1) {
                isPass = null; // 黃/灰色
                statusText = "尚未修習";
            }


            // 決定顯示的分數：如果有數字分數就顯示數字，沒有就顯示英文字母(P/T/F)
            var displayScore = scoreVal !== "" ? scoreVal : passStatus;


            // 組合學期名稱：如果原本只有寫「一(年)」，就要根據欄位補上「上」或「下」
            var term = yearLabel;
            // 如果文字不包含上或下，且我們正在處理上下學期的特定 td
            if (yearLabel.indexOf("上") === -1 && yearLabel.indexOf("下") === -1) {
                term = yearLabel.replace("年)", "") + semSuffix + ")";
            }


            results.push({
                term: term,
                subject: subject,
                score: displayScore,
                credit: credit,
                type: type,
                className: "", // 此表格無班級資訊
                isPass: isPass,
                status: statusText,
            });
        }


        // 分別處理上學期 (tds[5]) 與 下學期 (tds[6])
        processSemester(tds[5], "上");
        processSemester(tds[6], "下");
    });


    // 統一使用 postMessage 發送結果
    if (results.length > 0) {
        window._hasParsedScore = true;
        if (window.mobileApp) {
            window.mobileApp.postMessage({
                detail: { type: "DATA_SUCCESS", payload: results },
            });
        }
    }
})();

news.webviewScript:
(function () {
  // 全域鎖：防止重複執行回傳
  if (window._hasParsedNews) return;

  var rows = document.querySelectorAll('.listTB tbody tr');
  if (rows.length === 0) return; // 等待表格載入完成

  window._hasParsedNews = true;
  var result = [];

  for (var i = 0; i < rows.length; i++) {
    var tr = rows[i];
    var titleA = tr.querySelector('td[data-th="標題"] a');
    var dateTd = tr.querySelector('td[data-th="日期"]');
    var deptTd = tr.querySelector('td[data-th="發佈單位"]');

    if (titleA) {
      var cleanDate = dateTd ? dateTd.textContent.replace(/[\s\[\]]/g, '') : '';

      result.push({
        title: titleA.textContent.trim(),
        date: cleanDate,
        link: titleA.href,
        department: deptTd ? deptTd.textContent.trim() : '校方公告'
      });
    }
  }

  if (window.mobileApp) {
    window.mobileApp.postMessage({
      detail: {
        type: 'NEWS_SUCCESS',
        payload: result
      }
    });
  }
})();
